#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-27

set -euo pipefail

# Route Map for /ork:expect (Phase 3)
# Usage: bash route-map.sh [file1 file2 ...]
# If no args, reads changed files from stdin (one per line)
# Output: JSON mapping changed files → testable URLs

# ── Collect changed files ─────────────────────────────────
if [[ $# -gt 0 ]]; then
  CHANGED_FILES=("$@")
else
  CHANGED_FILES=()
  while IFS= read -r line; do
    [[ -n "$line" ]] && CHANGED_FILES+=("$line")
  done
fi

if [[ ${#CHANGED_FILES[@]} -eq 0 ]]; then
  echo '{"framework":"unknown","routes":{},"unmapped":[]}'
  exit 0
fi

# ── Detect framework ─────────────────────────────────────
detect_framework() {
  if [[ -d "src/app" ]] && find src/app -name "page.tsx" -o -name "page.jsx" 2>/dev/null | head -1 | grep -q .; then
    echo "nextjs-app"
  elif [[ -d "app" ]] && find app -maxdepth 3 -name "page.tsx" -o -name "page.jsx" 2>/dev/null | head -1 | grep -q .; then
    echo "nextjs-app"
  elif [[ -d "src/pages" ]] || [[ -d "pages" ]]; then
    echo "nextjs-pages"
  elif [[ -d "app/routes" ]] && find app/routes -name "*.tsx" -o -name "*.jsx" 2>/dev/null | head -1 | grep -q .; then
    echo "remix"
  elif [[ -d "src/routes" ]] && find src/routes -name "+page.svelte" 2>/dev/null | head -1 | grep -q .; then
    echo "sveltekit"
  else
    echo "unknown"
  fi
}

FRAMEWORK=$(detect_framework)

# ── Framework-specific: file path → URL ───────────────────
file_to_url() {
  local file="$1"

  case "$FRAMEWORK" in
    nextjs-app)
      # src/app/about/page.tsx → /about
      # src/app/page.tsx → /
      # app/dashboard/page.tsx → /dashboard
      if echo "$file" | grep -qE '(src/app|^app)/.*page\.(tsx|jsx|ts|js)$'; then
        local route
        route=$(echo "$file" | sed -E 's#^(src/)?app/##; s#/page\.(tsx|jsx|ts|js)$##; s#^\.$##')
        # Replace [param] with placeholder
        route=$(echo "$route" | sed -E 's#\[([^]]+)\]#{\1}#g')
        echo "/${route}"
        return 0
      fi
      ;;
    nextjs-pages)
      # pages/index.tsx → /
      # src/pages/about.tsx → /about
      # pages/blog/[slug].tsx → /blog/{slug}
      if echo "$file" | grep -qE '(src/pages|^pages)/.*\.(tsx|jsx|ts|js)$'; then
        local route
        route=$(echo "$file" | sed -E 's#^(src/)?pages/##; s#\.(tsx|jsx|ts|js)$##')
        [[ "$route" == "index" ]] && route=""
        route=$(echo "$route" | sed -E 's#/index$##; s#\[([^]]+)\]#{\1}#g')
        echo "/${route}"
        return 0
      fi
      ;;
    remix)
      # app/routes/_index.tsx → /
      # app/routes/about.tsx → /about
      # app/routes/blog.$slug.tsx → /blog/{slug}
      if echo "$file" | grep -qE '^app/routes/.*\.(tsx|jsx|ts|js)$'; then
        local route
        route=$(echo "$file" | sed -E 's#^app/routes/##; s#\.(tsx|jsx|ts|js)$##')
        [[ "$route" == "_index" ]] && route=""
        route=$(echo "$route" | sed 's#\.#/#g; s#\$\([a-zA-Z_]*\)#{\1}#g; s#_index$##')
        echo "/${route}"
        return 0
      fi
      ;;
    sveltekit)
      # src/routes/+page.svelte → /
      # src/routes/about/+page.svelte → /about
      # src/routes/blog/[slug]/+page.svelte → /blog/{slug}
      if echo "$file" | grep -qE '^src/routes/.*/?\+page\.svelte$'; then
        local route
        route=$(echo "$file" | sed -E 's#^src/routes/##; s#/?\+page\.svelte$##')
        route=$(echo "$route" | sed -E 's#\[([^]]+)\]#{\1}#g')
        echo "/${route}"
        return 0
      fi
      ;;
  esac
  return 1
}

# ── Level 2: Find which pages import a component ─────────
find_importing_pages() {
  local component="$1"
  local basename
  basename=$(basename "$component" | sed -E 's#\.(tsx|jsx|ts|js)$##')

  # Grep for imports of this file across page files
  local page_pattern
  case "$FRAMEWORK" in
    nextjs-app)   page_pattern='page\.(tsx|jsx|ts|js)$' ;;
    nextjs-pages) page_pattern='\.(tsx|jsx|ts|js)$' ;;
    remix)        page_pattern='\.(tsx|jsx|ts|js)$' ;;
    sveltekit)    page_pattern='\+page\.svelte$' ;;
    *)            page_pattern='\.(tsx|jsx|ts|js|svelte|vue)$' ;;
  esac

  # Search for import/require of this component name
  grep -rlE "(import .* from .*${basename}|require\(.*${basename})" \
    --include="*.tsx" --include="*.jsx" --include="*.ts" --include="*.js" --include="*.svelte" \
    . 2>/dev/null \
    | grep -E "$page_pattern" \
    | sed 's#^\./##' \
    || true
}

# ── Level 3: Config override (.expect/config.yaml) ───────
config_lookup() {
  local file="$1"
  if [[ -f ".expect/config.yaml" ]]; then
    python3 -c "
import sys, yaml, fnmatch
try:
    with open('.expect/config.yaml') as f:
        cfg = yaml.safe_load(f) or {}
    route_map = cfg.get('route_map', {})
    for pattern, urls in route_map.items():
        if fnmatch.fnmatch('${file}', pattern):
            for u in (urls if isinstance(urls, list) else [urls]):
                print(u)
except Exception:
    pass
" 2>/dev/null || true
  fi
}

# ── Build route map ───────────────────────────────────────
# Associative arrays: route → files[], unmapped files
declare -A ROUTE_FILES
UNMAPPED=()

for file in "${CHANGED_FILES[@]}"; do
  [[ -z "$file" ]] && continue

  # Skip non-source files
  if echo "$file" | grep -qE '\.(lock|log|map|md|json|yaml|yml)$|node_modules/|\.git/|dist/|build/'; then
    continue
  fi

  MAPPED=false

  # Level 3 (highest priority): config.yaml route_map
  while IFS= read -r url; do
    [[ -z "$url" ]] && continue
    ROUTE_FILES["$url"]+="${file}"$'\n'
    MAPPED=true
  done < <(config_lookup "$file")

  # Level 1: Direct page file → URL
  if url=$(file_to_url "$file" 2>/dev/null); then
    ROUTE_FILES["$url"]+="${file}"$'\n'
    MAPPED=true
  fi

  # Level 2: Component imported by pages
  if [[ "$MAPPED" == "false" ]]; then
    while IFS= read -r page_file; do
      [[ -z "$page_file" ]] && continue
      if page_url=$(file_to_url "$page_file" 2>/dev/null); then
        ROUTE_FILES["$page_url"]+="${file}"$'\n'
        MAPPED=true
      fi
    done < <(find_importing_pages "$file")
  fi

  if [[ "$MAPPED" == "false" ]]; then
    UNMAPPED+=("$file")
  fi
done

# ── Output JSON via python3 ──────────────────────────────
python3 -c "
import json, sys

framework = '${FRAMEWORK}'

# Parse routes from env-passed data
routes = {}
$(for url in "${!ROUTE_FILES[@]}"; do
    FILES_FOR_URL="${ROUTE_FILES[$url]}"
    echo "for f in '''${FILES_FOR_URL}'''.strip().splitlines():"
    echo "    routes.setdefault('${url}', []);"
    echo "    if f.strip() and f.strip() not in routes['${url}']: routes['${url}'].append(f.strip())"
done)

unmapped = [u for u in '''$(printf '%s\n' "${UNMAPPED[@]}")'''.strip().splitlines() if u.strip()]

result = {
    'framework': framework,
    'routes': dict(sorted(routes.items())),
    'unmapped': unmapped
}

print(json.dumps(result, indent=2))
"
